        loadData: function (tabName) {
            var vm = this;
            if (tabName == 'TicketSummary') {
                vm.activeKey = 1;
                vm.TicketSummarytab = true;
                vm.TicketPrivilegeTab = false;
                vm.TicketDetailsTab = false;
                vm.headerText = 'Ticket Summary Report';
