            try {
                return decodeURIComponent(encodedName);
            } catch (e) {
                return encodedName;
            }
        },

        // Initialize tab from route query parameter
        initializeTabFromRoute() {
            const tabParam = this.$route.query.tab;

            if (tabParam) {
                const decodedTabName = this.decodeTabName(tabParam);
                // Map tab names to loadData parameter
                const tabMap = {
                    'TicketSummary': 'TicketSummary',
                    'TicketPrivilege': 'TicketPrivilege',
                    'TicketDetails': 'TicketDetails'
                };

                if (tabMap[decodedTabName]) {
                    // Tab found, load it
                    this.loadData(tabMap[decodedTabName]);
                } else {
                    // Tab not found, fallback to first tab and update URL
                    this.loadData('TicketSummary');
                    this.$router.replace({
                        path: '/TicketReport/Index',
                        query: { tab: this.encodeTabName('TicketSummary') }
                    }).catch(() => { });
                }
            } else {
                // No tab in URL, add current tab to URL
                const currentTabName = this.activeKey === 1 ? 'TicketSummary' :
                    (this.activeKey === 2 ? 'TicketPrivilege' : 'TicketDetails');
                this.$router.replace({
                    path: '/TicketReport/Index',
                    query: { tab: this.encodeTabName(currentTabName) }
                }).catch(() => { });
            }
        },
